/* AF font canon — Geist (sans) + Geist Mono (mono).
 *
 * IMPORTANT: load Geist via <link rel="stylesheet"> in your document <head>:
 *
 *   <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
 *   <link rel="stylesheet" href="https://fonts.googleapis.com/css2?family=Geist:wght@400;500;600;700&family=Geist+Mono:wght@400;500&display=swap">
 *
 * Why not `@import url(...)` here? Tailwind v4 / PostCSS pipelines concatenate
 * af-tokens.css AFTER other CSS rules, which makes the @import illegal
 * (CSS spec: @import must precede all other statements). The compiled bundle
 * then drops the import silently and Geist never loads. The <link> approach
 * is the same byte-cost and works in every pipeline. Joe-flagged 2026-05-17. */

:root {
  /* Base AF tokens — Damian-canon */
  --af-ink:        #010E26;
  --af-ink-muted:  #14233E;
  --af-pulse:      #60A5FA;
  --af-paper:      #FFFFFF;

  /* ─── Typography ───────────────────────────────────────────────────────
   * Font canon: Geist (sans) for everything UI/body, Geist Mono for code,
   * timestamps, numeric counts, story-IDs. Letter-spacing tightens with
   * size — AF brand convention (Damian-canon): large display = tighter,
   * small caption = normal, eyebrow micro-text = looser tracking.
   * ─────────────────────────────────────────────────────────────────── */

  /* Font families */
  --af-font-sans:  'Geist', -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
  --af-font-mono:  'Geist Mono', ui-monospace, SFMono-Regular, Menlo, monospace;

  /* Semantic weights — use these, not raw numbers */
  --af-weight-regular:   400;  /* body */
  --af-weight-medium:    500;  /* UI elements, buttons, chips */
  --af-weight-semibold:  600;  /* headlines, emphasis */
  --af-weight-bold:      700;  /* hero display, callouts */

  /* Type scale — 9 named usages, each with size/line-height/tracking.
   * Sizes lean a touch larger than typical web defaults (AF prefers
   * generous, readable type at the cost of density). Tracking values come
   * from Geist's own design recommendations + AF brand observations. */

  /* Display — hero / opening headline (use 1-2× per page max) */
  --af-text-display-size:      56px;
  --af-text-display-line:      1.05;
  --af-text-display-tracking:  -0.024em;

  /* H1 — page title */
  --af-text-h1-size:           44px;
  --af-text-h1-line:           1.08;
  --af-text-h1-tracking:       -0.018em;

  /* H2 — section heading */
  --af-text-h2-size:           28px;
  --af-text-h2-line:           1.15;
  --af-text-h2-tracking:       -0.014em;

  /* H3 — sub-section heading */
  --af-text-h3-size:           20px;
  --af-text-h3-line:           1.25;
  --af-text-h3-tracking:       -0.008em;

  /* Body — default running text (paragraphs, lede) */
  --af-text-body-size:         16px;
  --af-text-body-line:         1.55;
  --af-text-body-tracking:     -0.003em;

  /* UI — buttons, chips, labels, form fields */
  --af-text-ui-size:           14px;
  --af-text-ui-line:           1.45;
  --af-text-ui-tracking:       0.005em;

  /* Caption — small meta text, footers, secondary info */
  --af-text-caption-size:      12px;
  --af-text-caption-line:      1.45;
  --af-text-caption-tracking:  0.005em;

  /* Mono — code, story-IDs, timestamps, numeric counts */
  --af-text-mono-size:         13px;
  --af-text-mono-line:         1.45;
  --af-text-mono-tracking:     0;

  /* Eyebrow — small uppercase pulse-blue text above headlines */
  --af-text-eyebrow-size:      11px;
  --af-text-eyebrow-line:      1;
  --af-text-eyebrow-tracking:  0.12em;

  /* Pulse glow variants — for AFVQ underglows, hover states, focus rings */
  --af-pulse-glow-06:  rgba(96, 165, 250, 0.06);
  --af-pulse-glow-12:  rgba(96, 165, 250, 0.12);
  --af-pulse-glow-18:  rgba(96, 165, 250, 0.18);
  --af-pulse-glow-20:  rgba(96, 165, 250, 0.20);
  --af-pulse-glow-28:  rgba(96, 165, 250, 0.28);
  --af-pulse-glow-30:  rgba(96, 165, 250, 0.30);
  --af-pulse-glow-50:  rgba(96, 165, 250, 0.50);

  /* Ink glow variants — subtle shadows on light backgrounds */
  --af-ink-glow-04:    rgba(1, 14, 38, 0.04);
  --af-ink-glow-08:    rgba(1, 14, 38, 0.08);
  --af-ink-glow-10:    rgba(1, 14, 38, 0.10);
  --af-ink-glow-16:    rgba(1, 14, 38, 0.16);
  --af-ink-glow-30:    rgba(1, 14, 38, 0.30);

  /* Surface variants — Radix-style 12-step layered hierarchy */
  --af-surface-1:      var(--af-paper);
  --af-surface-2:      rgba(1, 14, 38, 0.02);
  --af-surface-3:      rgba(1, 14, 38, 0.04);
  --af-surface-4:      rgba(1, 14, 38, 0.08);

  /* Border variants */
  --af-border-subtle:  rgba(1, 14, 38, 0.10);
  --af-border-strong:  rgba(1, 14, 38, 0.20);

  /* Canonical easings */
  --af-ease-out-soft:  cubic-bezier(0.16, 1, 0.3, 1);

  /* ─── MacBook chassis tones ────────────────────────────────────────────
   * Apple-canon hex approximations per
   * ~/Anfragenfluss-style/audits/macbook-pro-m4-mockup.md §4.
   * Calibration: medium (community-canonical photographic samples of apple.com
   * hero renders; Apple does not publish official hex values).
   * Consumed by the macbook-pro-chassis component `variant` prop. Don't use
   * directly — go through the component so chassis geometry and shadow stay paired.
   * ─────────────────────────────────────────────────────────────────── */
  --af-chassis-space-black:      #1D1D1F;
  --af-chassis-space-black-edge: #3A3A3D;
  --af-chassis-space-black-base: #2D2D2F;
  --af-chassis-space-gray:       #3A3A3C;
  --af-chassis-space-gray-edge:  #505053;
  --af-chassis-space-gray-base:  #2C2C2E;
  --af-chassis-silver:           #D7D9DD;
  --af-chassis-silver-edge:      #B3B6BC;
  --af-chassis-silver-base:      #C0C3C8;
}

/* OKLCH variants (Tailwind v4 default) — use these on new builds.
 * Verify perceptual match before locking; original canon was authored in sRGB. */
@supports (color: oklch(0 0 0)) {
  :root {
    --af-ink-oklch:        oklch(0.14 0.04 252);
    --af-ink-muted-oklch:  oklch(0.24 0.05 252);
    --af-pulse-oklch:      oklch(0.74 0.13 245);
    --af-paper-oklch:      oklch(1.00 0.00 0);
  }
}
